      var first = history[0], last = history[history.length - 1];
      var delta = last - first;
      var trend = delta > 8 ? 'жҢҒз»ӯдёҠеҚҮ' : delta > 3 ? 'зј“ж…ўдёҠеҚҮ' : delta < -8 ? 'жҖҘеү§иЎ°иҗҪ' : delta < -3 ? 'зј“ж…ўиЎ°иҗҪ' : 'еҹәжң¬зЁіе®ҡ';
