  var _virtuousKeywords = /ж”№йқ©|ж•ҙйҘ¬|иӮғжё…|еҮҸзЁҺ|иҪ»иөӢ|иөҲзҒҫ|е…ҙдҝ®|ж“Қз»ғ|ж•ҙйЎҝ|е·ЎжҹҘ|зқЈеҠһ|йқ©ејҠ|жғ©иҙӘ|ејҖд»“|жҠҡж°‘|з§‘дёҫ|йҖүиҙӨ|дёҘжҹҘ|й—®иҙЈ|жё…жҹҘ/;
  var _edictWordCount = allEdictText.length;
