    if (GM._energy !== undefined) {
      var _enRatio = GM._energy / (GM._energyMax || 100);
      if (_enRatio < 0.3) tp += '\nгҖҗеҗӣдё»зІҫеҠӣдёҘйҮҚдёҚи¶і(' + Math.round(GM._energy) + '/' + (GM._energyMax||100) + ')вҖ”вҖ”еҸҷдәӢдҪ“зҺ°з–Іжғ«гҖҒеҲӨж–ӯеҠӣдёӢйҷҚгҖҒжҳ“жҖ’жҲ–жҒҚжғҡгҖ‘\n';
      else if (_enRatio < 0.5) tp += '\nгҖҗеҗӣдё»з•Ҙжҳҫз–ІжҖҒ(' + Math.round(GM._energy) + '/' + (GM._energyMax||100) + ')вҖ”вҖ”еҸҷдәӢеҸҜжҡ—зӨәеӨ„зҗҶж”ҝеҠЎзЁҚжҳҫиҝҹзј“гҖ‘\n';
      else if (_enRatio > 0.9) tp += '\nгҖҗеҗӣдё»зІҫеҠӣе……жІӣвҖ”вҖ”еҸҷдәӢеҸҜдҪ“зҺ°зҘһйҮҮеҘ•еҘ•гҖҒеҶіж–ӯжһңж•ўгҖ‘\n';
    }

    // P14: жҲҗе°ұйҮҢзЁӢзў‘жіЁе…ҘпјҲи®©AIеңЁеҸҷдәӢдёӯе‘јеә”зҺ©е®¶жҲҗе°ұпјү
    if (GM._achievements && GM._achievements.length > 0) {
      var _recentAch = GM._achievements.filter(function(a) { return GM.turn - a.turn <= 2; });
      if (_recentAch.length > 0) {
        tp += '\nгҖҗиҝ‘жңҹйҮҢзЁӢзў‘вҖ”вҖ”еҸҜеңЁеҸҷдәӢдёӯиҮӘз„¶дҪ“зҺ°гҖ‘\n';
        _recentAch.forEach(function(a) { tp += '  В· ' + a.name + 'пјҡ' + a.desc + '\n'; });
      }
    }

    // E10: дё–д»Јдј жүҝдәӢд»¶жіЁе…Ҙ
    if (GM._successionEvent) {
      tp += '\nгҖҗйҮҚеӨ§дәӢд»¶вҖ”вҖ”еёқдҪҚжӣҙиҝӯпјҲеҝ…йЎ»еңЁеҸҷдәӢдёӯжө“еўЁйҮҚеҪ©жҸҸеҶҷпјүгҖ‘\n';
      tp += 'е…Ҳеёқ' + GM._successionEvent.from + 'й©ҫеҙ©пјҲеҺҹеӣ пјҡ' + (GM._successionEvent.reason||'жңӘзҹҘ') + 'пјүпјҢ';
      tp += 'ж–°еҗӣ' + GM._successionEvent.to + 'е·Із»§дҪҚгҖӮжңқе ӮйңҮеҠЁпјҢзҫӨиҮЈи§ӮжңӣгҖӮ\n';
      delete GM._successionEvent; // еҸӘжіЁе…ҘдёҖж¬Ў
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // гҖҗзҺ©е®¶еңЈж„ҸВ·жң¬еӣһеҗҲВ·ж¬Ўй«ҳдјҳе…Ҳзә§гҖ‘пјҲдҪҺдәҺдёҠж–№"й—®еӨ©"зӣҙжҺҘжҢҮд»ӨВ·й«ҳдәҺеёёи§„иғҢжҷҜпјү
    // жұҮжҖ»зҺ©е®¶йҖҡиҝҮжңқи®®/з§‘и®®/иҜҸд»Ө/еҘҸз–Ҹ/й—®еҜ№дҪңеҮәзҡ„жІ»еӣҪеҶізӯ–В·
    // AI жҺЁжј”йЎ»пјҡ(1) еҸҷдәӢеҝ…еӣһеә” (2) зӣёе…і NPC еҝ…е“Қеә” (3) жү§иЎҢеҸ—жҢ«еҝ…дәӨд»ЈеҺҹеӣ 
    // дёҚеҸҜеҒҮиЈ…жІЎеҸ‘з”ҹВ·дҪҶеҸҜж №жҚ®зҺ°е®һпјҲиҙўж”ҝ/и·қзҰ»/еҸІе®һ/дәәе‘ҳпјүжҺЁжј”жҲҗеҠҹ/йғЁеҲҶ/еҸ—йҳ»/еӨұиҙҘ
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    tp += '\n\nв•җв•җв•җ гҖҗзҺ©е®¶еңЈж„ҸВ·ж¬Ўй«ҳдјҳе…Ҳзә§гҖ‘в•җв•җв•җ\n';
    tp += 'д»ҘдёӢжҳҜжң¬еӣһеҗҲзҺ©е®¶йҖҡиҝҮжӯЈеёёжІ»еӣҪжүӢж®өдҪңеҮәзҡ„еҶізӯ–В·еҝ…йЎ»еңЁжҺЁжј”дёӯеҫ—еҲ°дҪ“зҺ°дёҺе“Қеә”пјҡ\n';
    tp += 'вҖ» жӯӨзә§еҲ«дҪҺдәҺдёҠж–№"й—®еӨ©"зӣҙжҺҘжҢҮд»ӨВ·дҪҶй«ҳдәҺдёҖеҲҮеёёи§„иғҢжҷҜгҖӮжҺЁжј”ж•ҲжһңеҸҜеҸ—зҺ°е®һзәҰжқҹВ·дҪҶдёҚеҫ—иў«еҝҪз•ҘгҖӮ\n';
    tp += 'вҖ» жҜҸжқЎеҶізӯ–йЎ»еңЁеӣһеҗҲиҫ“еҮәзҡ„еҗ„еӯ—ж®өдёӯдҪ“зҺ°вҖ”вҖ”дҫӢеҰӮпјҡ\n';
    tp += '    В· zhengwenпјҲж—¶ж”ҝи®°В·еҪ“жңҲжңқе ӮеҸҷдәӢпјүиҰҒжңүеҜ№еә”ж®өиҗҪиҜҙжҳҺиҜҸд»ӨйўҒиЎҢгҖҒжңқи®®иҗҪе®һгҖҒеҘҸз–Ҹжү№еӨҚжү§иЎҢжғ…еҶө\n';
    tp += '    В· eventsпјҲдәӢд»¶/е®һеҪ•пјүиҰҒи®°дёӢеј•еҸ‘зҡ„йҮҚеӨ§еҠЁдҪңпјҲеҰӮжҙҫе‘ҳгҖҒиө·е…өгҖҒеҫҒеҸ¬гҖҒе·ҘзЁӢејҖе·Ҙпјү\n';
    tp += '    В· npc_actionsпјҲеҗҺдәәжҲҸиҜҙ/дёӘдәәиЎҢжӯўпјүиҰҒи®©зӣёе…іе®ҳе‘ҳдҪңеҮәеҜ№еә”е“Қеә”пјҲжҺЁиҝӣ/жҠөеҲ¶/и§„йҒҝ/дёҠз–Ҹз”іиҫ©пјү\n';
    tp += '    В· edict_feedbackпјҲж•°еҖјеҸҳеҢ–иҜҙжҳҺпјүиҰҒз»ҷеҮәеҸ—жҢ«/жҲҗеҠҹзҡ„еҺҹеӣ дёҺеҪұе“Қ\n';
    tp += 'вҖ» дёҚеҝ…йҮҮз”Ёеӣәе®ҡжЁЎжқҝВ·еҲҶе·Ҙе‘ҲзҺ°еҚіеҸҜпјӣдҪҶдёҚеҫ—еҒҮиЈ…жІЎеҸ‘з”ҹВ·дёҚеҫ—и®©зҺ©е®¶еҶізӯ–ж·№жІЎеңЁиғҢжҷҜеҸҷдәӢдёӯгҖӮ\n\n';

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // гҖҗеҸҷдәӢ-зҠ¶жҖҒеҗҢжӯҘВ·ж ёеҝғеҺҹеҲҷгҖ‘вҖ”вҖ”жҺЁжј”еҸҷдәӢеҝ…йЎ»иҗҪеӣһзңҹе®һжёёжҲҸж•°жҚ®
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    tp += '\nв•җв•җв•җ гҖҗеҸҷдәӢ-зҠ¶жҖҒеҗҢжӯҘВ·ж ёеҝғеҺҹеҲҷгҖ‘в•җв•җв•җ\n';
    tp += 'вҖ» еҮЎжҺЁжј”еҸҷдәӢдёӯжҸҸеҶҷзҡ„"е®һйҷ…еҸ‘з”ҹзҡ„еҸҳеҢ–"В·еқҮйЎ»йҖҡиҝҮеҜ№еә”зҡ„иҜӯд№үйҖҡйҒ“иҗҪеӣһжёёжҲҸзҠ¶жҖҒеӯ—ж®өВ·дёҚеҫ—еҸӘеҒңз•ҷеңЁж–Үеӯ—жҸҸиҝ°пјҡ\n';
    tp += '  В· зҡҮеёқиөҗеҗҚ/ж”№еҗҚ X дёә Y вҶ’ char_updates:[{name:"X",updates:{name:"Y",еҺҹеҗҚ:"X"}}]В·еҗҢжӯҘеҲ·ж–° careerHistory ж Үйўҳ\n';
    tp += '  В· зҺ©е®¶ж”№е®ҳиҒҢеҗҚпјҲдҫӢ"жҲ·йғЁе°ҡд№Ұ"вҶ’"еәҰж”Ҝд»Ө"пјүвҶ’ anyPathChanges ж”№ P.officeTree еҜ№еә”иҠӮзӮ№В·е№¶еҜ№жүҖжңү officialTitle==ж—§еҗҚ зҡ„ char еҗҢжӯҘ char_updates.updates.officialTitle\n';
    tp += '  В· жҺҲе®ҳ вҶ’ office_assignments:[{name,post,dept,action:"appoint",toLocation?,reason}]В·иӢҘйңҖиөҙд»»еҲҷз•ҷиө°дҪҚпјӣеҗҢж—¶ careerEvent иҮӘеҠЁиҝҪеҠ пјҢж— йңҖеҚ•зӢ¬еҶҷ\n';
    tp += '  В· зҪўе…Қ/иҙ¬и°Ә/еӨ–ж”ҫ вҶ’ office_assignments action:"dismiss"/"transfer"пјӣеҰӮеӨ–ж”ҫйЎ» toLocation+иө°дҪҚ\n';
    tp += '    вҳ…гҖҗејәеҲ¶В·дёҚиҰҒеҸӘеҶҷ personnel_changesгҖ‘personnel_changes д»…дҫӣеҸІи®°еј№зӘ—еұ•зӨәВ·дёҚдјҡзңҹжӯЈж”№еҠЁе®ҳеҲ¶ж ‘/дәәзү©д»•йҖ”В·еҝ…йЎ»еҗҢж—¶еңЁ office_assignments йҮҢеҶҷз»“жһ„еҢ–жқЎзӣ®В·еҗҰеҲҷе®ҳиҒҢдёҚз”ҹж•Ҳ\n';
    tp += '    вҳ… жҳ е°„пјҡзҺ©е®¶иҜҸд»Ө"е‘Ҫ X дёә Y" вҶ’ office_assignments:[{name:"X",post:"Y",action:"appoint"}]В·дё” personnel_changes йҮҢеҗҢжӯҘеҶҷдёҖжқЎдҫӣеұ•зӨә\n';
    tp += '    вҳ… зҺ©е®¶зҪўжҹҗдәә вҶ’ office_assignments action:"dismiss" + personnel_changes еҗҢеҶҷВ·дёӨеӨ„еҝ…й…ҚеҘ—\n';
    tp += '  В· е°ҒзҲө/иөҗеҸ·/иҝҪи°Ҙ вҶ’ char_updates.updates йҮҢжӣҙж–° title/зҲөдҪҚ/е°ҒеҸ·В·е№¶ careerEvent и®°еҪ•\n';
    tp += '  В· иөҗжӯ»/иҜӣжҲ®/жҠ„е®¶ вҶ’ char_updates.updates.alive:false жҲ– onDismissal reason:"execute"\n';
    tp += '  В· ж–°и®ҫ/иЈҒж’ӨиЎҷй—Ё вҶ’ anyPathChanges ж”№ P.officeTreeпјӣеҗҢж—¶е»әз«Ӣ/и§ЈйҷӨеҜ№еә” publicTreasury з»‘е®ҡ\n';
    tp += '  В· иҙўж”ҝи°ғж•ҙпјҲиөҗйҮ‘/еҫҒеҸ‘/дё“ж¬ҫ/зјҙиҺ·/иҙЎе“Ғ/иө”ж¬ҫ/зҪҡжІЎ/иөҲжөҺпјүвҶ’ fiscal_adjustments:[{target:"guoku|neitang|province:X",kind:"income|expense",resource:"money|grain|cloth",amount,name,reason,recurring:false}]\n';
    tp += '    вҳ…гҖҗејәеҲ¶В·ж ёеҝғ bug еҺҶеҸІж•ҷи®ӯгҖ‘д»»дҪ•й’ұ/зІ®/еёғжөҒеҠЁвҖ”вҖ”ж— и®әжҳҜзҺ©е®¶иҜҸд»ӨжүҖеј•пјҲиөҸй“¶дёҮдёӨВ·иөҲзІ®еҚғзҹіВ·дҝ®е®«ж®ҝВ·еҸ‘еҶӣйҘ·пјүВ·иҝҳжҳҜжҺЁжј”дёӯзҡ„ NPC иЎҢдёәпјҲиҙӘжұЎВ·иҙЎзәіВ·зјҙиҺ·В·иө”ж¬ҫВ·иө°з§Ғе…Ҙеә“пјүВ·еҝ…йЎ»дёҖжқЎдёҖжқЎеҶҷе…Ҙ fiscal_adjustmentsВ·з»қдёҚеҸҜеҸӘеңЁеҸҷдәӢ/жҲҸиҜҙ/е®һеҪ•йҮҢжҸҗеҸҠж•°еӯ—иҖҢдёҚиҗҪиҙҰ\n';
    tp += '    вҳ… еёёи§Ғжҳ е°„пјҡзҡҮеёқиөҗиөҸз§ҒдәәвҶ’target:neitang/kind:expenseпјӣиҜҸд»ӨиөҲжөҺең°ж–№вҶ’target:guoku/kind:expenseпјӣжҲҳдәүзјҙиҺ·вҶ’target:guoku/kind:incomeпјӣең°ж–№иҙЎзү©вҶ’target:guoku/kind:incomeпјҲиҙөйҮҚзҸҚе®қеҲҷ neitangпјүпјӣжҠ„е®¶зҪҡжІЎвҶ’guoku жҲ– neitangпјҲи§Ҷжғ…пјү\n';
    tp += '    вҳ… recurring:true еҸӘз”ЁдәҺй•ҝжңҹе№ҙдҫӢпјҲеҰӮ"еІҒиөҗиҫҪдёңйҘ·дёүеҚҒдёҮ"пјүпјӣдёҖж¬ЎжҖ§иөҸиөҗ/иөҲжөҺ/зјҙиҺ· recurring:falseпјҲз«ӢеҲ»дҪңз”ЁдәҺдҪҷйўқпјҢдёҚз»ӯпјү\n';
    tp += '    вҳ… зҺ©е®¶иҜҸд»Өж–Үжң¬иӢҘеҮәзҺ°жҳҺзЎ®ж•°йўқпјҲиөҸ/иөҗ/жӢЁ/еҸ‘/еҫҒ/жҠ„/жІЎпјүX дёӨ/зҹі/еҢ№вҖ”вҖ”еҝ…йЎ»з”ҹжҲҗеҜ№еә” fiscal_adjustmentsпјӣиӢҘеә“дёҚи¶іеҲҷ kind:expense еҸӘиғҪеҲ°еә“дҪҷпјҢе№¶еңЁ reason йҮҢиҜҙжҳҺ"еә“дёҚи¶ід»…жӢЁ N"\n';
    tp += '    вҳ…гҖҗжү§иЎҢдёҠйҷҗВ·дёҚеҫ—зӘҒз ҙ 0гҖ‘зҺ©е®¶дё»еҠЁиҠұй’ұжңҖеӨҡиҠұеҲ°еә“еӯҳи§Ғеә•пјҢдёҚиғҪйҖҸж”ҜеҲ°иҙҹж•°пјҡ\n';
    tp += '        - иӢҘ её‘е»Ә/еҶ…её‘ дҪҷйўқ <= 0пјҲиў«еҠЁз»“з®—еҗҺе·ІиөӨеӯ—пјүвҶ’ жң¬жқЎиҜҸд»Ө expense е®Ңе…Ёж— жі•жү§иЎҢпјҲapplier дјҡж Ү executionStatus:blockedпјү\n';
    tp += '        - иӢҘ 0 < дҪҷйўқ < иҜ·ж¬ҫйўқ вҶ’ жӢЁеҲ°и§Ғеә•В·еү©дҪҷи®°дәҸж¬ пјҲexecutionStatus:partialпјү\n';
    tp += '        - edict_feedback еҜ№еә”жқЎзӣ®еҝ…йЎ»жҚ®жӯӨз»ҷеҮәеҗҺжһңпјҡblockedвҶ’"еӣҪеә“з©әиҷҡВ·иҜҸдёҚеҫ—иЎҢВ·жҹҗдәӢеӣ жӯӨеҒңйЎҝ/жҝҖеҸҳ"пјӣpartialвҶ’"д»…жӢЁ N дёӨ/зҹіВ·дёҚи¶ійғЁеҲҶеҰӮдҪ•жҺӘзҪ®пјҲеҠ жҙҫ/еҖҹиҙ·/жҢӘз§»/жӢ–ж¬ пјү"\n';
