    if(GM.keju && GM.keju.preparingExam) tp+="\u79D1\u4E3E\u7B79\u529E\u4E2D\uFF0C\u8BF7\u5728\u6B63\u6587\u4E2D\u5C55\u793A\u8FDB\u5C55\u3002\n";
