    tp += 'жҜҸдёӘNPCеңЁжҜҸеӣһеҗҲйғҪз»ҸеҺҶдёҖдёӘеҶ…еҝғеҶізӯ–иҝҮзЁӢпјҲдҪ дёҚйңҖиҰҒиҫ“еҮәжӯӨиҝҮзЁӢпјҢдҪҶеҝ…йЎ»жҚ®жӯӨеҶіе®ҡе…¶иЎҢдёәпјүпјҡ\n';
    tp += '  1. жҲ‘зҡ„еӨ„еўғеҰӮдҪ•пјҹвҖ”вҖ”еҝ иҜҡ/еҺӢеҠӣ/йҮҺеҝғж•°еҖј + жңҖиҝ‘з»ҸеҺҶпјҲеҸӮиҖғеҝғз»Әи®°еҝҶпјү\n';
    tp += '     иў«иЎЁжү¬вҶ’иҮӘдҝЎиҶЁиғҖпјӣиў«еҶ·иҗҪвҶ’жҖЁжҒЁз§ҜзҙҜпјӣиў«иғҢеҸӣвҶ’дҝЎд»»еҙ©еЎҢ\n';
    tp += '  2. жҲ‘еңЁж„Ҹд»Җд№ҲпјҹвҖ”вҖ”personalGoalжҳҜеҗҰиў«ж»Ўи¶іпјҹзҰ»зӣ®ж Үжӣҙиҝ‘иҝҳжҳҜжӣҙиҝңдәҶпјҹ\n';
    tp += '     зӣ®ж Үж»Ўи¶іеәҰй«ҳвҶ’е®үеҲҶе®Ҳе·ұпјӣзӣ®ж ҮеҸ—жҢ«вҶ’й“ӨиҖҢиө°йҷ©\n';
    tp += '  3. и°ҒжҳҜжҲ‘зҡ„зӣҹеҸӢгҖҒи°ҒжҳҜжҲ‘зҡ„ж•ҢдәәпјҹвҖ”вҖ”дәІз–Ҹе…ізі» + жҒ©жҖЁи®°еҪ•\n';
    tp += '     жҒ©дәәжңүйҡҫвҶ’жӢје‘Ҫзӣёж•‘пјӣд»Үдәәеҫ—еҠҝвҶ’жҡ—дёӯз ҙеқҸ\n';
    tp += '  4. еҪ“еүҚеұҖеҠҝеҜ№жҲ‘жңүеҲ©иҝҳжҳҜдёҚеҲ©пјҹвҖ”вҖ”еҠҝеҠӣж јеұҖгҖҒе…ҡжҙҫеҪўеҠҝгҖҒеҗӣдё»жҖҒеәҰ\n';
    tp += '     еұҖеҠҝжңүеҲ©вҶ’жү©еӨ§дјҳеҠҝпјҲдёҫиҚҗеҗҢе…ҡгҖҒжү“еҮ»ејӮе·ұпјүпјӣдёҚеҲ©вҶ’йҹ¬е…үе…»жҷҰжҲ–еӯӨжіЁдёҖжҺ·\n';
