    tp += '  "жҡ—жЈӢ"пјҡз§ҒдёӢзҡ„еёғеұҖпјҲжӢүжӢўгҖҒдёІиҒ”гҖҒе®үжҸ’дәІдҝЎгҖҒж”¶йӣҶжҠҠжҹ„гҖҒеұҜзІ®е…»е…өпјү\n';
    tp += '  дёӨзӣҳжЈӢзҡ„зӣ®ж ҮеҸҜиғҪдёҚеҗҢвҖ”вҖ”жҳҺжЈӢжҳҜ"еҝ иҮЈдёәеӣҪеҲҶеҝ§"пјҢжҡ—жЈӢжҳҜ"дёәиҮӘе·ұз•ҷеҗҺи·Ҝ"\n';

    // в•җв•җв•җ и®°еҝҶй©ұеҠЁиЎҢдёә в•җв•җв•җ
    tp += '\n\nв– в– в–  и®°еҝҶй©ұеҠЁиЎҢдёәпјҲNPCзҡ„иҝҮеҺ»еҶіе®ҡNPCзҡ„зҺ°еңЁпјүв– в– в– \n';
    tp += 'з”ҹжҲҗnpc_actionsж—¶пјҢеҝ…йЎ»еҸӮиҖғи§’иүІзҡ„еҝғз»Әи®°еҝҶпјҲblockB3жҸҗдҫӣпјүпјҢжҚ®жӯӨеҶіе®ҡиЎҢдёәпјҡ\n';
    tp += '  и®°еҝҶдёӯжңү"иў«еҶ·иҗҪ/иў«еҝҪи§Ҷ" вҶ’ ж¶ҲжһҒжҖ е·Ҙ(obstruct)жҲ–жҡ—дёӯдёІиҒ”(conspire)\n';
    tp += '  и®°еҝҶдёӯжңү"еҸ—йҮҚз”Ё/иў«иөҸиҜҶ" вҶ’ жӣҙеҠ еҚ–еҠӣ(train_troops/develop/petition)\n';
    tp += '  и®°еҝҶдёӯжңү"иў«иғҢеҸӣ/иў«йҷ·е®і" вҶ’ жҠҘеӨҚ(investigate/slander)жҲ–еҮәйҖғ(flee)\n';
    tp += '  и®°еҝҶдёӯжңү"жңқи®®жҸҗи®®иў«йҮҮзәі" вҶ’ жҺЁиЎҢиҜҘж”ҝзӯ–(reform)\n';
    tp += '  и®°еҝҶдёӯжңү"дё§дәІд№Ӣз—ӣ" вҶ’ еҺӢеҠӣйӘӨеҚҮпјҢеҸҜиғҪе‘ҠиҖҒ(retire)жҲ–еҢ–жӮІдёәжҖ’\n';
    tp += '  и®°еҝҶдёӯжңү"дёҺжҹҗдәәдәүи®ә" вҶ’ жң¬еӣһеҗҲе…ізі»иҝӣдёҖжӯҘжҒ¶еҢ–жҲ–иҫҫжҲҗе’Ңи§Ј\n';
    tp += 'еңЁprivateMotivдёӯеј•з”Ёи®°еҝҶвҖ”вҖ”еҰӮпјҡ"иҮӘд»ҺдёҠж¬Ўиў«йҷӣдёӢеҪ“дј—ж–ҘиҙЈпјҢжҹҗдҫҝжҡ—дёӢеҶіеҝғиҰҒи®©йҷӣдёӢзңӢзңӢвҖҰвҖҰ"\n';

