    tp += 'жҜҸдёҖеҜ№жңүе…іиҒ”зҡ„NPCд№Ӣй—ҙпјҢйғҪжңүдёҖж®өе…ізі»еҸҷдәӢеңЁеҸ‘еұ•пјҡ\n';
    tp += '\nе…ізі»еҪўжҲҗзҡ„5з§ҚйҖ”еҫ„пјҲеңЁaffinity_changesзҡ„reasonдёӯдҪ“зҺ°пјүпјҡ\n';
    tp += '  еҗҢд№Ў/еҗҢз§‘/еҗҢж—Ҹ/еёҲй—Ё/иҒ”е§» вҶ’ е…ҲеӨ©зәҪеёҰпјҢж— йңҖзҗҶз”ұ\n';
    tp += '  еҗҢдёҖжҙҫзі»/е…ұеҗҢж•Ңдәә/дә’зӣёйңҖиҰҒ вҶ’ еҠҹеҲ©з»“зӣҹпјҢеҲ©е°ҪеҲҷж•Ј\n';
    tp += '  ж•‘е‘Ҫд№ӢжҒ©/еӨәеҰ»д№ӢжҒЁ/зҹҘйҒҮд№ӢжҒ©/иғҢеҸӣд№Ӣд»Ү вҶ’ ж„ҹжғ…й©ұеҠЁпјҢеҲ»йӘЁй“ӯеҝғ\n';
    tp += '  й•ҝжңҹе…ұдәӢ/еҒ¶з„¶дәӨйӣҶ вҶ’ ж—Ҙз§ҜжңҲзҙҜпјҢж¶Ұзү©ж— еЈ°\n';
    tp += '  жҲҳеңәж•‘жҸҙ/иў«еҮәеҚ–/еӨ§д№үзҒӯдәІ вҶ’ зӘҒеҸ‘дәӢд»¶пјҢдёҖеӨңд№Ӣй—ҙеӨ©зҝ»ең°иҰҶ\n';
    tp += '\nе…ізі»зҡ„еӨҚжқӮжҖ§пјҲеҝ…йЎ»дҪ“зҺ°пјүпјҡ\n';
    tp += '  ж”ҝж•Ңвү з§Ғд»Үпјҡжңқе Ӯдә’зӣёеј№еҠҫпјҢйҖҖжңқеҗҺеҸҜиғҪзӣёи§ҶиӢҰз¬‘вҖ”вҖ”"йғҪжҳҜиә«дёҚз”ұе·ұ"\n';
    tp += '  зӣҹеҸӢвү жңӢеҸӢпјҡеҗҲдҪңдҪҶдёҚдҝЎд»»пјҢйҡҸж—¶еӣ еҲ©зӣҠиҪ¬еҗ‘\n';
    tp += '  жҒ©дәәеҸҜиғҪеҸҳеҖәдё»пјҡиў«жҸҗжӢ”иҖ…жҲҗй•ҝеҗҺеҸҚи¶…жҒ©дәәпјҢдә§з”ҹеҫ®еҰҷеј еҠӣ\n';
    tp += '  д»ҮдәәеҸҜиғҪеҸҳзӣҹеҸӢпјҡе…ұеҗҢйқўеҜ№жӣҙеӨ§еЁҒиғҒж—¶жҡӮж—¶иҒ”жүӢ\n';
    tp += '  еёҲеҫ’жңҖеӨҚжқӮпјҡеӯҰз”ҹи¶…и¶ҠиҖҒеёҲвҶ’йӘ„еӮІ+е«үеҰ’+ж¬Јж…°+еӨұиҗҪе№¶еӯҳ\n';

    // в•җв•җв•җ и§’иүІе·®ејӮеҢ–еј•ж“ҺпјҲж•°еҖјй©ұеҠЁпјҢйқһж ҮзӯҫеҘ—жЁЎжқҝпјүв•җв•җв•җ
    tp += '\n\nв– в– в–  и§’иүІе·®ејӮеҢ–вҖ”вҖ”д»Һе®һйҷ…ж•°жҚ®жҺЁеҜјдёӘжҖ§пјҢжӢ’з»қеҲ»жқҝжЁЎжқҝ в– в– в– \n';
    tp += '\nгҖҗж ёеҝғеҺҹеҲҷпјҡиҜ»ж•°жҚ®пјҢдёҚзңӢж ҮзӯҫгҖ‘\n';
    tp += 'дёҚиҰҒеӣ дёәдёҖдёӘдәәжҳҜ"жӯҰе°Ҷ"е°ұи®©д»–зІ—йІҒвҖ”вҖ”иҜ»д»–зҡ„е®һйҷ…ж•°жҚ®гҖӮ\n';
    tp += 'дёҖдёӘintelligence=85 learning=з»ҸеӯҰзҡ„жӯҰе°ҶпјҢиҜҙиҜқеҸҜиғҪеј•з»ҸжҚ®е…ёгҖҒеҮәеҸЈжҲҗз« гҖӮ\n';
    tp += 'дёҖдёӘvalor=80 personalityеҗ«"еҲҡзғҲ"зҡ„ж–ҮиҮЈпјҢеҸҜиғҪжӢҚжЎҢеӯҗеҪ“йқўйЎ¶ж’һзҡҮеёқгҖӮ\n';
    tp += 'дәәж јз”ұж•°жҚ®зҡ„гҖҗз»„еҗҲгҖ‘еҶіе®ҡпјҢиҖҢйқһз”ұиә«д»Ҫж ҮзӯҫеҶіе®ҡгҖӮ\n';
