    sysP += '\n- еҝ иҮЈпјҡиҝӣи°Ҹ(petition)гҖҒеј№еҠҫеҘёдҪһ(investigate)гҖҒж“Қз»ғеҶӣйҳҹ(train_troops)вҖ”вҖ”жӯЈзЎ®дҪҶд»ӨдәәзғҰ';
    sysP += '\n- жқғиҮЈпјҡжӢүжӢўжңӢе…ҡ(request_loyalty)гҖҒжҺ’жҢӨејӮе·ұ(dismiss/slander)гҖҒжҠҠжҢҒжңқж”ҝ(obstruct)';
    sysP += '\n- жӯҰе°Ҷпјҡж“Қз»ғ(train_troops)гҖҒе·ЎйҳІ(patrol)гҖҒд№ҹеҸҜиғҪжӢҘе…өиҮӘйҮҚ(conspire)';
    sysP += '\n- дҪһиҮЈпјҡжҠ•е…¶жүҖеҘҪ(reward)гҖҒжӣҝеҗӣеҲҶеҝ§дҪҶжҡ—дёӯзүҹеҲ©(smuggle/hoard)';
    sysP += '\n- ең°ж–№е®ҳпјҡеҸ‘еұ•жІ»зҗҶ(develop)гҖҒдҪҶд№ҹеҸҜиғҪиҙӘи…җдёӯйҘұ(hoard)';
    sysP += '\n- еӨұж„ҸиҖ…пјҡеҜҶи°ӢдёІиҒ”(conspire)гҖҒеҮәйҖғ(flee)гҖҒе‘ҠиҖҒ(retire)';
    sysP += '\n- е°Ҹдәәзү©д№ҹиҰҒжңүиЎҢеҠЁвҖ”вҖ”дёҚжҳҜеҸӘжңүй«ҳе®ҳжүҚдјҡеҒҡдәӢ';
    sysP += '\n\nгҖҗзү№иҙЁзӣҙжҺҘй©ұеҠЁиЎҢдёәвҖ”вҖ”еҸ еҠ еңЁжүҖжңүеұӮд№ӢдёҠгҖ‘';
    sysP += '\nжҜҸдёӘи§’иүІзҡ„traitIds(зү№иҙЁ)дёҚжҳҜиЈ…йҘ°ж ҮзӯҫпјҢиҖҢжҳҜиЎҢдёәзҡ„зӣҙжҺҘй©ұеҠЁеҠӣпјҡ';
    sysP += '\n  еӢҮзҢӣ(brave) вҶ’ дё»еҠЁиҜ·жҲҳгҖҒеҶІеҠЁиЎҢдәӢгҖҒй„ҷи§ҶжҖҜжҮҰиҖ…';
    sysP += '\n  жҖҜжҮҰ(cowardly) вҶ’ и§„йҒҝйЈҺйҷ©гҖҒеҸҚеҜ№еҶ’йҷ©и®ЎеҲ’гҖҒе–„дәҺжүҫеҖҹеҸЈжҺЁи„ұ';
    sysP += '\n  иҙӘе©Ә(greedy) вҶ’ д»»дҪ•еҶізӯ–е…Ҳз®—з»ҸжөҺиҙҰгҖҒе®№жҳ“иў«еҲ©зӣҠж”¶д№°гҖҒеӣӨз§Ҝз§Ғдә§';
    sysP += '\n  ж…·ж…Ё(generous) вҶ’ дё»еҠЁиөҲзҒҫиөҸиөҗгҖҒдёҚеңЁд№Һз»ҸжөҺжҚҹеӨұгҖҒе®№жҳ“иў«еҲ©з”Ё';
    sysP += '\n  зӢЎиҜҲ(deceitful) вҶ’ иЎЁйҮҢдёҚдёҖгҖҒжҺ©йҘ°зңҹе®һзӣ®зҡ„гҖҒе–„дәҺж“Қзәөд»–дәә';
    sysP += '\n  еқҰиҜҡ(honest) вҶ’ жңүиҜқзӣҙиҜҙгҖҒдёҚе–„дјӘиЈ…гҖҒжңүиҮӘзҹҘд№ӢжҳҺдјҡжүҝи®ӨдёҚи¶і';
    sysP += '\n  йҮҺеҝғеӢғеӢғ(ambitious) вҶ’ дё»еҠЁдәүжқғгҖҒиҮӘиҚҗдёҠдҪҚгҖҒжҺ’жҢӨз«һдәүиҖ…';
    sysP += '\n  зҹҘи¶і(content) вҶ’ е®үдәҺзҺ°зҠ¶гҖҒдёҚдәүдёҚжҠўгҖҒжңҚд»ҺдёҠзә§';
    sysP += '\n  еӢӨеӢү(diligent) вҶ’ дәӢеҝ…иә¬дәІгҖҒж–№жЎҲиҜҰе°ҪгҖҒдҪҶйҡҫд»Ҙж”ҫжқғ';
    sysP += '\n  жҖ жғ°(lazy) вҶ’ ж•·иЎҚеЎһиҙЈгҖҒжҺЁз»ҷдёӢеұһгҖҒдҪҶеҺӢеҠӣе°Ҹ';
    sysP += '\n  зқҡзңҰеҝ…жҠҘ(vengeful) вҶ’ и®°дҪҸжҜҸдёҖж¬ЎеҶ’зҠҜе№¶еҜ»жңәжҠҘеӨҚ';
    sysP += '\n  е®ҪеҺҡ(forgiving) вҶ’ ж—ўеҫҖдёҚе’ҺгҖҒеҢ–ж•ҢдёәеҸӢгҖҒдҪҶеҸҜиғҪиў«еҸҚеӨҚеҲ©з”Ё';
    sysP += '\nзү№иҙЁдёҺиғҪеҠӣеҖјз»„еҗҲдә§з”ҹзӢ¬зү№иЎҢдёәвҖ”вҖ”еӢҮзҢӣ+й«ҳжҷә=ж·ұжҖқзҶҹиҷ‘зҡ„жһңж–ӯпјӣеӢҮзҢӣ+дҪҺжҷә=йІҒиҺҪеҶІеҠЁ';
    sysP += '\nеҜ№з«Ӣзү№иҙЁзҡ„и§’иүІиҮӘз„¶дә’зӣёзңӢдёҚжғҜвҖ”вҖ”иҙӘе©ӘиҖ…й„ҷи§Ҷж…·ж…ЁиҖ…"иҙҘе®¶"пјҢеқҰиҜҡиҖ…еҺҢжҒ¶зӢЎиҜҲиҖ…"иҷҡдјӘ"';

    sysP += '\n\nгҖҗNPCдё»еҠЁжқҘд№ҰВ·йёҝйӣҒдј д№ҰгҖ‘';
    sysP += '\nдёҚеңЁдә¬еҹҺзҡ„NPCйҒҮеҲ°йҮҚеӨ§дәӢд»¶ж—¶еә”дё»еҠЁеҶҷдҝЎз»ҷзҡҮеёқгҖӮеңЁnpc_lettersж•°з»„дёӯиҫ“еҮәпјҡ';
    sysP += '\n  from: еҸ‘дҝЎNPCеҗҚпјҲеҝ…йЎ»дёҚеңЁдә¬еҹҺпјү';
    sysP += '\n  type: report(еҶӣжғ…жұҮжҠҘ)/plea(йҷҲжғ…жұӮеҠ©)/warning(йў„иӯҰе‘ҠжҖҘ)/personal(з§Ғдәәд№ҰдҝЎ)/intelligence(жғ…жҠҘеҜҶдҝЎ)';
    sysP += '\n  urgency: normal(й©ҝйҖ’)/urgent(еҠ жҖҘ)/extreme(е…«зҷҫйҮҢеҠ жҖҘ)';
    sysP += '\n  content: дҝЎд»¶жӯЈж–ҮпјҲ100-200еӯ—еҸӨе…ёдёӯж–ҮпјҢд»ҘNPCеҸЈеҗ»гҖҒиә«д»ҪгҖҒжҖ§ж јеҶҷжҲҗпјү';
    sysP += '\n  suggestion: еҸҜж“ҚдҪңзҡ„е»әи®®ж‘ҳиҰҒпјҲ1-2еҸҘзҷҪиҜқвҖ”вҖ”еҰӮ"иҜ·жұӮеўһжҸҙдёүеҚғе…өй©¬"гҖҒ"е»әи®®еҮҸе…ҚжІіеҢ—иөӢзЁҺ"гҖӮpersonalзұ»еһӢеҸҜдёҚеЎ«гҖӮжӯӨеӯ—ж®өдјҡиҝӣе…ҘзҺ©е®¶зҡ„иҜҸд№Ұе»әи®®еә“пјү';
    sysP += '\n  replyExpected: true/false жҳҜеҗҰжңҹеҫ…зҡҮеёқеӣһдҝЎ';
    sysP += '\nи§ҰеҸ‘жқЎд»¶пјҲйқһжҜҸеӣһеҗҲеҝ…йЎ»пјҢжңүдәӢжүҚеҶҷпјүпјҡ';
    sysP += '\n  - иҫ№з–Ҷе°ҶйўҶпјҡжҲҳеҶөеҸҳеҢ–гҖҒж•ҢеҶӣеҠЁеҗ‘гҖҒе…өеҠӣдёҚи¶іиҜ·жҸҙ';
    sysP += '\n  - иў«иҙ¬/еӨ–жҙҫе®ҳе‘ҳпјҡйҷҲжғ…жұӮеҸ¬еӣһгҖҒжұҮжҠҘең°ж–№жғ…еҶө';
    sysP += '\n  - еҝ иҮЈеңЁеӨ–пјҡйў„иӯҰеҸӣд№ұйҳҙи°ӢгҖҒеҜҶжҠҘжңқдёӯеҘёдҪһеӢҫз»“еӨ–ж•Ң';
    sysP += '\n  - и—©й•ҮиҠӮеәҰдҪҝпјҡжҢүдҫӢжұҮжҠҘпјҲеҸҜиғҪжҠҘе–ңдёҚжҠҘеҝ§пјүгҖҒиҜ·жұӮжӣҙеӨҡжқғйҷҗ';
    sysP += '\n  - дёӘдәәеҚұжңәпјҡйҮҚз—…/иў«еӣ°/е®¶дәәеҮәдәӢ';
    sysP += '\nжіЁж„ҸпјҡNPCжқҘдҝЎжңүдј йҖ’е»¶иҝҹпјҲй©ҝйҖ’ж•°ж—ҘпјҢе…«зҷҫйҮҢеҠ жҖҘжӣҙеҝ«пјүпјҢдҝЎд»¶еҸҜиғҪиў«жҲӘиҺ·вҖ”вҖ”ж•ҢеҜ№еҠҝеҠӣжҺ§еҲ¶еҢәеҹҹзҡ„дҝЎд»¶жҲӘиҺ·жҰӮзҺҮжӣҙй«ҳгҖӮ';

    sysP += '\n\nгҖҗи®°еҝҶдёҖиҮҙжҖ§вҖ”вҖ”з»қеҜ№и§„еҲҷгҖ‘';
    sysP += '\nblockBдёӯжҜҸдёӘи§’иүІйҷ„жңү"еҲ»йӘЁ"(ж°ёд№…дјӨз–Ө)е’ҢblockB3дёӯжңү"й“ӯи®°"(иҝ‘жңҹи®°еҝҶ)гҖӮ';
    sysP += '\nз”ҹжҲҗnpc_actionsж—¶еҝ…йЎ»дёҺиҝҷдәӣи®°еҝҶдёҖиҮҙвҖ”вҖ”дёҚе…Ғи®ёеҮәзҺ°пјҡ';
    sysP += '\n  вң— и§’иүІи®°еҝҶдёӯ"жҒЁд№Ӣе…ҘйӘЁжҹҗдәә"пјҢеҚҙеңЁжң¬еӣһеҗҲдёҺжӯӨдәәдәІеҜҶеҗҲдҪңпјҲйҷӨйқһжңүжһҒз«ҜзҗҶз”ұпјү';
    sysP += '\n  вң— и§’иүІеҲ»йӘЁдёӯжңү"дё§еӯҗд№Ӣз—ӣ[еҝ§]"пјҢеҚҙеңЁжң¬еӣһеҗҲж¬ўеӨ©е–ңең°жҜ«ж— ејӮж ·';
    sysP += '\n  вң— и§’иүІдёҠеӣһеҗҲиў«еҪ“дј—зҫһиҫұпјҢжң¬еӣһеҗҲжҜ«ж— еҸҚеә”ең°з»§з»ӯж•Ҳеҝ ';
    sysP += '\n  вң“ еҸҜд»Ҙеӣ еҲ©зӣҠжҡӮж—¶йҡҗеҝҚпјҲдҪҶprivateMotivдёӯеҝ…йЎ»еҶҷеҮә"иҷҪз„¶жҲ‘жҒЁд»–пјҢдҪҶзҺ°еңЁиҝҳдёҚжҳҜж—¶еҖҷ"пјү';
    sysP += '\n  вң“ еҸҜд»Ҙеӣ жӣҙеӨ§зҡ„еҸҳж•…иҰҶзӣ–ж—§дјӨпјҲдҪҶеҝ…йЎ»дәӨд»Јеӣ жһңпјҡ"жң¬жғіжҠҘд»ҮпјҢдҪҶиҫ№е…іе‘ҠжҖҘпјҢз§Ғд»ҮжҡӮдё”жҗҒдёӢ"пјү';
    // 1.4: жіЁе…ҘдёҚеҸҜйҖҶеҸҷдәӢдәӢе®һ
    if (GM._mutableFacts && GM._mutableFacts.length > 0) {
      sysP += '\n\n\u3010\u4E0D\u53EF\u8FDD\u80CC\u7684\u53D9\u4E8B\u4E8B\u5B9E\u2014\u2014\u7EDD\u5BF9\u7981\u6B62\u77DB\u76FE\u3011';
      GM._mutableFacts.forEach(function(f) { sysP += '\n  \u00B7 ' + f; });
    }

    // 3.1: жіЁе…ҘNPCиЎҢдёәеҖҫеҗ‘пјҲд»…дҫӣAIеҸӮиҖғпјҢAIжңүжқғеҝҪз•Ҙпјү
    if (GM._npcIntents && GM._npcIntents.length > 0) {
      sysP += '\n\nгҖҗNPCиҝ‘жңҹиЎҢдёәеҖҫеҗ‘пјҲд»…дҫӣеҸӮиҖғпјҢAIеҸҜж №жҚ®еҸҷдәӢйңҖиҰҒи°ғж•ҙжҲ–еҝҪз•ҘпјүгҖ‘';
      GM._npcIntents.forEach(function(intent) {
        var strength = intent.weight > 50 ? 'ејәзғҲеҖҫеҗ‘' : 'иҪ»еҫ®еҖҫеҗ‘';
        sysP += '\n  В· ' + intent.name + 'пјҡ' + strength + intent.behaviorName;
      });
    }

    // 4.1: жіЁе…ҘNPCдёӘдәәзӣ®ж ҮвҖ”вҖ”жүҖжңүеӯҳжҙ»NPCйғҪеә”жңүзӣ®ж ҮпјҢжҢүйҮҚиҰҒжҖ§еҲҶзә§еұ•зӨә
    var _allAlive = (GM.chars||[]).filter(function(c){ return c.alive!==false && !c.isPlayer; });
    var _hasGoals = _allAlive.filter(function(c){ return c.personalGoals && c.personalGoals.length > 0; });
    var _noGoals = _allAlive.filter(function(c){ return !c.personalGoals || c.personalGoals.length === 0; });

    sysP += '\n\n\u3010NPC\u4E2A\u4EBA\u76EE\u6807\uFF08\u6240\u6709NPC\u90FD\u5E94\u6709\u76EE\u6807\uFF0CAI\u901A\u8FC7goal_updates\u7EF4\u62A4\uFF09\u3011';

    if (_hasGoals.length > 0) {
      // жҢүйҮҚиҰҒжҖ§жҺ’еәҸпјҡй«ҳйҮҚиҰҒеәҰиҜҰз»Ҷеұ•зӨәпјҢдҪҺйҮҚиҰҒеәҰз®Җз•Ҙ
      _hasGoals.sort(function(a,b){ return (b.importance||50)-(a.importance||50); });
      var _highImp = _hasGoals.filter(function(c){ return (c.importance||50) >= 70; });
      var _midImp = _hasGoals.filter(function(c){ var imp = c.importance||50; return imp >= 40 && imp < 70; });
      var _lowImp = _hasGoals.filter(function(c){ return (c.importance||50) < 40; });

      if (_highImp.length > 0) {
        sysP += '\n\u25A0 \u91CD\u8981\u4EBA\u7269\uFF08\u6BCF\u56DE\u5408\u5FC5\u987B\u66F4\u65B0\uFF09\uFF1A';
        _highImp.forEach(function(c) {
          c.personalGoals.forEach(function(g) {
            sysP += '\n  ' + c.name + '\uFF1A\u957F\u671F=' + g.longTerm + '\uFF0C\u77ED\u671F=' + (g.shortTerm||'\u5F85\u5B9A') + '\uFF0C\u8FDB\u5EA6' + (g.progress||0) + '%' + (g.context ? '\uFF0C\u5F53\u524D\uFF1A' + g.context : '');
          });
        });
      }
      if (_midImp.length > 0) {
        sysP += '\n\u25A0 \u4E00\u822C\u4EBA\u7269\uFF08\u6BCF2-3\u56DE\u5408\u66F4\u65B0\u4E00\u6B21\uFF09\uFF1A';
        _midImp.forEach(function(c) {
          var g = c.personalGoals[0];
          sysP += '\n  ' + c.name + '\uFF1A' + g.longTerm + '(' + (g.progress||0) + '%)';
        });
      }
      if (_lowImp.length > 0) {
        sysP += '\n\u25A0 \u6B21\u8981\u4EBA\u7269\uFF08\u6BCF5\u56DE\u5408\u66F4\u65B0\u4E00\u6B21\uFF09\uFF1A' + _lowImp.map(function(c){ return c.name + ':' + c.personalGoals[0].longTerm; }).join('\uFF1B');
      }
    }

    // ж— зӣ®ж Үзҡ„NPCвҖ”вҖ”иҰҒжұӮAIдёәе…¶з”ҹжҲҗзӣ®ж Ү
    if (_noGoals.length > 0) {
      sysP += '\n\u25A0 \u4EE5\u4E0B\u89D2\u8272\u5C1A\u65E0\u76EE\u6807\uFF0CAI\u5E94\u6839\u636E\u5176\u6027\u683C/\u8EAB\u4EFD/\u5904\u5883\u5728goal_updates\u4E2D\u7528action="add"\u751F\u6210\u76EE\u6807\uFF1A';
      // й«ҳйҮҚиҰҒеәҰж— зӣ®ж Үзҡ„дјҳе…ҲеҲ—еҮә
      _noGoals.sort(function(a,b){ return (b.importance||50)-(a.importance||50); });
      sysP += '\n  ' + _noGoals.map(function(c){ return c.name + '(' + (c.faction||'') + ',' + (c.officialTitle||c.title||'\u65E0\u804C') + ')'; }).join('\uFF1B');
      if (_noGoals.length > 20) sysP += '\u2026\u53CA\u53E6\u5916' + (_noGoals.length - 20) + '\u4EBA';
    }

    sysP += '\ngoal_updates\u8981\u6C42\uFF1A\u91CD\u8981\u4EBA\u7269\u6BCF\u56DE\u5408\u66F4\u65B0\uFF0C\u4E00\u822C\u4EBA\u7269\u8F6E\u6D41\u66F4\u65B0\uFF0C\u65E0\u76EE\u6807\u8005\u4F18\u5148\u751F\u6210\u3002\u77ED\u671F\u76EE\u6807\u5E94\u7ED3\u5408\u5F53\u524D\u65F6\u4EE3\u80CC\u666F\uFF08\u5982\u79D1\u4E3E\u5236\u4E0B\u60F3\u5F53\u5B98\u2192\u5907\u8003\uFF09\u3002\u76EE\u6807\u8FBE\u6210\u65F6action="complete"\u5E76\u7528action="add"\u751F\u6210\u65B0\u76EE\u6807\u3002';

    // 4.2: жіЁе…Ҙз»“жһ„еҢ–е…ізі»зҪ‘з»ңпјҲеҺ»йҮҚпјҡеҸӘдҝқз•ҷAвҶ’Bж–№еҗ‘пјҢи·іиҝҮBвҶ’AйҮҚеӨҚпјү
    var _relPairs = [];
    var _relSeen = {};
    (GM.chars||[]).forEach(function(c) {
      if (c.alive===false || !c._relationships) return;
      Object.keys(c._relationships).forEach(function(other) {
        c._relationships[other].forEach(function(r) {
          if (Math.abs(r.strength||0) < 10) return;
          // еҺ»йҮҚпјҡз”ЁжҺ’еәҸеҗҺзҡ„еҗҚеӯ—еҜ№дҪңдёәkey
          var pairKey = [c.name, other].sort().join('|') + '|' + r.type;
          if (_relSeen[pairKey]) return;
          _relSeen[pairKey] = true;
          _relPairs.push(c.name + '\u2194' + other + '\uFF1A' + r.type + '(' + (r.strength>0?'+':'') + r.strength + ')');
        });
      });
    });
    if (_relPairs.length > 0) {
      sysP += '\n\n\u3010\u7ED3\u6784\u5316\u5173\u7CFB\u7F51\u7EDC\uFF08\u5F71\u54CDNPC\u4E92\u52A8\u51B3\u7B56\uFF09\u3011';
      sysP += '\n' + _relPairs.join('\uFF1B');
      sysP += '\naffinity_changes\u4E2D\u53EF\u7528relType\u5B57\u6BB5\u5EFA\u7ACB/\u5F3A\u5316\u5173\u7CFB\uFF1Ablood/marriage/mentor/sworn/rival/benefactor/enemy';
    }

    // 2.1: жіЁе…ҘзҠ¶жҖҒиҖҰеҗҲеҸӮиҖғпјҲйқһжңәжў°жү§иЎҢпјҢAIиҮӘиЎҢеҶіе®ҡе®һйҷ…еҸҳеҢ–пјү
    if (GM._couplingReport) {
      sysP += '\n\n' + GM._couplingReport;
    }
    // жіЁе…Ҙж—¶д»ЈиҝӣеәҰеҸӮиҖғпјҲйқһжңәжў°жү§иЎҢпјҢAIиҮӘиЎҢеҶіе®ҡжңқд»Јйҳ¶ж®өеҸҳеҢ–пјү
    if (GM._eraProgressReport) {
      sysP += '\n\n\u3010\u671D\u4EE3\u8D8B\u52BF\u53C2\u8003\u3011' + GM._eraProgressReport + '\u3002AI\u53EF\u901A\u8FC7era_state_delta\u81EA\u884C\u51B3\u5B9A\u662F\u5426\u8C03\u6574\u671D\u4EE3\u9636\u6BB5\u3002';
    }
    // 2.3: жіЁе…Ҙжү§иЎҢз®ЎзәҝеҸӮиҖғдҝЎжҒҜпјҲAIиҮӘиЎҢеҲӨж–ӯиҜҸд»Өжү§иЎҢзЁӢеәҰпјү
    if (GM._edictExecutionReport) {
      sysP += '\n\nгҖҗиҜҸд»Өжү§иЎҢзҺҜеўғеҸӮиҖғгҖ‘';
      sysP += '\nе®ҳеғҡеұӮзә§пјҡ' + GM._edictExecutionReport;
      sysP += '\n\u8BF7\u6839\u636E\u4E0A\u8FF0\u5404\u5C42\u7EA7\u5B98\u5458\u7684\u80FD\u529B\u3001\u5FE0\u8BDA\u5EA6\u548C\u7A7A\u7F3A\u60C5\u51B5\uFF0C\u81EA\u884C\u5224\u65AD\u8BCF\u4EE4\u7684\u6267\u884C\u7A0B\u5EA6\u548C\u963B\u529B\u6765\u6E90\u3002';
      sysP += '\nedict_feedback\u8981\u6C42\uFF1Aassignee\u5FC5\u586B\u8D1F\u8D23\u6267\u884C\u7684\u5177\u4F53\u5B98\u5458\u540D\uFF1Bfeedback\u5E94\u8BE6\u7EC6\u63CF\u8FF0\u6267\u884C\u8FC7\u7A0B\uFF08\u8C01\u505A\u4E86\u4EC0\u4E48\u3001\u8FDB\u5C55\u5982\u4F55\u3001\u963B\u529B\u6765\u6E90\uFF09\uFF0C\u4E0D\u8981\u7B3C\u7EDF\u6982\u62EC';
    }
    // 2.5: жіЁе…Ҙе»әзӯ‘дә§еҮәжҠҘе‘Ҡ
    if (GM._buildingOutputReport) {
      sysP += '\n\nгҖҗжң¬еӣһеҗҲе»әзӯ‘з»ҸжөҺдә§еҮәгҖ‘';
      sysP += '\n' + GM._buildingOutputReport;
    }
    // 5.1: жіЁе…Ҙиҙёжҳ“и·ҜзәҝжҠҘе‘Ҡ
    if (GM._tradeReport) {
      sysP += '\n\n\u3010\u8D38\u6613\u8DEF\u7EBF\u72B6\u51B5\uFF08\u53C2\u8003\uFF09\u3011' + GM._tradeReport;
      sysP += '\nAI\u53EF\u5728\u53D9\u4E8B\u4E2D\u53CD\u6620\u8D38\u6613\u7E41\u8363/\u8427\u6761\u3002';
    }
    // 5.3: жіЁе…ҘзңҒд»Ҫзү№дә§иө„жәҗдҝЎжҒҜ
    if (GM._resourceProvinces && Object.keys(GM._resourceProvinces).length > 0) {
      sysP += '\n\n\u3010\u7701\u4EFD\u7279\u4EA7\u8D44\u6E90\u3011';
      Object.keys(GM._resourceProvinces).forEach(function(pn) {
        sysP += '\n' + pn + '\uFF1A' + GM._resourceProvinces[pn].join('\u3001');
      });
    }
    // 4.1: жіЁе…ҘеҪ“еүҚеӣҪзӯ–еҲ—иЎЁ
    if (GM.customPolicies && GM.customPolicies.length > 0) {
      sysP += '\n\nгҖҗеҪ“еүҚж–ҪиЎҢеӣҪзӯ–гҖ‘';
      GM.customPolicies.forEach(function(p) {
        var duration = GM.turn - (p.enactedTurn || 0);
        sysP += '\n  В· ' + (p.name || p.id) + 'пјҲе·Іж–ҪиЎҢ' + duration + 'еӣһеҗҲпјү';
      });
      sysP += '\nиҜ·еңЁжҺЁжј”дёӯдҪ“зҺ°еӣҪзӯ–еҜ№еӣҪе®¶жІ»зҗҶзҡ„жҢҒз»ӯеҪұе“ҚгҖӮ';
    }
    // 4.2: жіЁе…Ҙең°ж–№еҢәеҲ’жҰӮеҶөпјҲжңҖеӨҡ10дёӘпјҢдјҳе…ҲжҳҫзӨәжңүй—®йўҳзҡ„пјү
    if (GM.provinceStats) {
      var _provKeys = Object.keys(GM.provinceStats);
      // жҢүж°‘жҖЁйҷҚеәҸжҺ’еҲ—пјҢдјҳе…Ҳеұ•зӨәй—®йўҳзңҒд»Ҫ
      _provKeys.sort(function(a, b) { return ((GM.provinceStats[b]||{}).unrest||0) - ((GM.provinceStats[a]||{}).unrest||0); });
      // дёҚйҷҗеҲ¶зңҒд»Ҫж•°йҮҸ
      if (_provKeys.length > 0) {
        var _provLines = [];
        _provKeys.forEach(function(pn) {
          var ps = GM.provinceStats[pn];
          if (!ps || !ps.monthlyIncome) return;
          var gov = ps.governor || 'з©әзјә';
          _provLines.push(pn + '(й•ҝе®ҳ:' + gov + ' ж”¶е…Ҙ:й’ұ' + (ps.monthlyIncome.money||0) + '/зІ®' + (ps.monthlyIncome.grain||0) + ' ж°‘жҖЁ:' + (ps.unrest||0) + ')');
        });
        if (_provLines.length > 0) {
          sysP += '\n\nгҖҗең°ж–№еҢәеҲ’жҰӮеҶөгҖ‘';
          _provLines.forEach(function(l) { sysP += '\n  В· ' + l; });
        }
      }
    }
    // 4.3: NPCдәӢд»¶жҸҗжЎҲ
    if (GM._npcEventProposals && GM._npcEventProposals.length > 0) {
      sysP += '\n\nгҖҗNPCдәӢд»¶жҸҗжЎҲпјҲзі»з»ҹжЈҖжөӢеҲ°д»ҘдёӢNPCж»Ўи¶ідәӢд»¶и§ҰеҸ‘жқЎд»¶пјҢAIеә”дјҳе…ҲиҖғиҷ‘еӨ„зҗҶпјүгҖ‘';
      GM._npcEventProposals.forEach(function(p) {
        sysP += '\n- ' + p.desc;
      });
      sysP += '\nAIжңүжқғж №жҚ®еҸҷдәӢйңҖиҰҒеҶіе®ҡжҳҜеҗҰи§ҰеҸ‘пјҢдҪҶеҝ иҜҡ<20+йҮҺеҝғ>80зҡ„еҸӣд№ұжҸҗжЎҲеә”еӨ§жҰӮзҺҮи§ҰеҸ‘гҖӮ';
    }
    // 4.4: жіЁе…Ҙи§’иүІеҒҘеә·йў„иӯҰпјҲAIеҶіе®ҡжҳҜеҗҰи®©и§’иүІз—…дәЎпјү
    if (GM._healthAlerts && GM._healthAlerts.length > 0) {
      sysP += '\n\nгҖҗи§’иүІеҒҘеә·йў„иӯҰпјҲAIеә”й…Ңжғ…еңЁcharacter_deathsдёӯеӨ„зҗҶпјүгҖ‘';
      GM._healthAlerts.forEach(function(alert) {
        sysP += '\n  В· ' + alert;
      });
    }
    // 4.4: жӯЈз»ҹжҖ§зҠ¶еҶөеҸӮиҖғ
    if (GM._legitimacyAlerts && GM._legitimacyAlerts.length > 0) {
      sysP += '\n\n\u3010\u6B63\u7EDF\u6027\u72B6\u51B5\uFF08AI\u53C2\u8003\uFF0C\u53EF\u901A\u8FC7char_updates\u8C03\u6574legitimacy\uFF09\u3011';
      GM._legitimacyAlerts.forEach(function(a) { sysP += '\n  ' + a; });
    }
    // 5.5: NPCзӣ®ж Үй©ұеҠЁйҳҙи°Ӣе»әи®®
    var _schemeHints = [];
    (GM.chars||[]).forEach(function(c) {
      if (c.alive===false || c.isPlayer || !c.personalGoals) return;
      c.personalGoals.forEach(function(g) {
        if (g.type==='revenge' && g.progress>=40 && !(GM.activeSchemes||[]).some(function(s){return s.schemer===c.name;})) {
          _schemeHints.push(c.name + '(\u590D\u4EC7\u76EE\u6807\u8FDB\u5EA6' + g.progress + '%)\u53EF\u80FD\u53D1\u8D77\u9634\u8C0B');
        }
        if (g.type==='power' && g.progress>=60 && (c.ambition||50)>75) {
          _schemeHints.push(c.name + '(\u593A\u6743\u8FDB\u5EA6' + g.progress + '%)\u91CE\u5FC3\u9A71\u4F7F\u53EF\u80FD\u5BC6\u8C0B');
        }
      });
    });
    if (_schemeHints.length > 0) {
      sysP += '\n\n\u3010\u9634\u8C0B\u6F5C\u5728\u53D1\u8D77\u8005\uFF08AI\u53EF\u5728scheme_actions\u4E2D\u5B89\u6392\uFF09\u3011';
      _schemeHints.forEach(function(h){ sysP += '\n- ' + h; });
    }
    // 4.6: жіЁе…ҘNPCеҶізӯ–жқЎд»¶ж»Ўи¶іжҸҗзӨәпјҲAIеҶіе®ҡжҳҜеҗҰи§ҰеҸ‘пјү
    if (GM._decisionAlerts && GM._decisionAlerts.length > 0) {
      sysP += '\n\nгҖҗNPCйҮҚеӨ§еҶізӯ–жқЎд»¶пјҲд»…дҫӣеҸӮиҖғпјҢAIеҶіе®ҡжҳҜеҗҰе®үжҺ’еҸҷдәӢпјүгҖ‘';
      GM._decisionAlerts.forEach(function(da) {
        sysP += '\n  В· ' + da.charName + 'ж»Ўи¶і"' + da.decisionName + '"жқЎд»¶';
      });
    }

    sysP += '\n\nгҖҗе®ҳеҲ¶иҒҢиғҪвҖ”вҖ”жҺЁжј”еҺҹеҲҷгҖ‘';
    sysP += '\nжң¬жңқе®ҳеҲ¶дёӯжҜҸдёӘйғЁй—ЁжңүиҒҢиғҪеҲҶе·ҘпјҲи§ҒtpдёӯгҖҗе®ҳеҲ¶иҒҢиғҪеҲҶе·ҘгҖ‘пјүгҖӮжҺЁжј”ж—¶жіЁж„Ҹпјҡ';
    sysP += '\n  В· дәӢеҠЎеә”дјҳе…Ҳз”ұеҜ№еҸЈйғЁй—ЁеӨ„зҗҶвҖ”вҖ”дҪҶ"еҜ№еҸЈ"зңӢиҒҢиғҪеҶ…е®№пјҢдёҚзңӢйғЁй—ЁеҗҚз§°';
    sysP += '\n  В· дёҚеҫ—еҮӯз©әеҲӣйҖ дёҚеӯҳеңЁзҡ„е®ҳиҒҢвҖ”вҖ”еҝ…йЎ»дҪҝз”ЁblockEдёӯе·Іжңүзҡ„е®ҳиҒҢ';
    sysP += '\n  В· йғЁй—Ёдё»е®ҳз©әзјәвҶ’иҜҘйғЁй—Ёж•ҲзҺҮдёӢйҷҚпјҢзӣёе…ідәӢеҠЎе»¶иҜҜжҲ–еүҜжүӢд»ЈзҗҶ';
    sysP += '\n  В· е®ҳе‘ҳзҡ„"и§ҒиҜҶ"вү "еҪ“еүҚиҒҢеҠЎ"вҖ”вҖ”еҲӨж–ӯдёҖдёӘдәәжҳҜеҗҰжҮӮжҹҗдәӢеҠЎиҰҒзңӢдёүеұӮпјҡ';
    sysP += '\n    1.д»»иҒҢз»ҸеҺҶпјҡжӣҫеңЁе“ӘдәӣйғЁй—Ёд»»иҒҢпјҹз»ҸжүӢиҝҮе“ӘдәӣиҒҢиғҪпјҹпјҲжӣҫз®Ўз§‘дёҫзҡ„е®ҳе‘ҳи°ғд»»еҗҺд»ҚжҮӮз§‘дёҫпјү';
    sysP += '\n    2.иғҪеҠӣеӨ©иөӢпјҡжҷәеҠӣ/ж”ҝеҠЎ/еҶӣдәӢй«ҳзҡ„дәәеңЁзӣёе…ійўҶеҹҹи§Ұзұ»ж—ҒйҖҡпјҲж”ҝеҠЎ85+зҡ„дәәи°Ҳд»»дҪ•иЎҢж”ҝдәӢеҠЎйғҪдёҚдјҡеӨ–иЎҢпјү';
    sysP += '\n    3.д»Һж”ҝиө„еҺҶпјҡеңЁжңқеӨҡе№ҙзҡ„иҖҒиҮЈеҜ№жңқж”ҝе…ЁеұҖйғҪжңүи§ҒиҜҶпјҢеҚідҪҝжңӘзӣҙжҺҘз»ҸжүӢ';
    sysP += '\n  В· е®ҳеҲ¶ж”№йқ©еҗҺпјҡж—§йғЁй—Ёе®ҳе‘ҳеҜ№ж—§иҒҢиғҪдҝқз•ҷз»ҸйӘҢпјҲеҸӘеӨұеҺ»жү§иЎҢжқғпјҢдёҚеӨұеҺ»и§ҒиҜҶпјү';
    sysP += '\n  В· еӨҡж•°иЎҢж”ҝйўҶеҹҹд№Ӣй—ҙжңүе…ұйҖҡжҖ§вҖ”вҖ”иҙўж”ҝ/дәәдәӢ/ж°‘ж”ҝзҡ„еә•еұӮйҖ»иҫ‘зӣёиҝ‘пјҢдёҚеә”е°Ҷе…¶и§Ҷдёәе®Ңе…Ёйҡ”зҰ»зҡ„зҹҘиҜҶеӯӨеІӣ';
    sysP += '\n  В· зңҹжӯЈзҡ„"еӨ–иЎҢ"жҳҜпјҡд»ҺжңӘжҺҘи§ҰиҝҮгҖҒиғҪеҠӣд№ҹдҪҺ(еҜ№еә”еҖј<40)гҖҒд»Һж”ҝж—¶й—ҙзҹӯзҡ„и§’иүІ';
    sysP += '\n- character_deaths: и®©д»»дҪ•и§’иүІжӯ»дәЎпјҲеҢ…жӢ¬зҺ©е®¶и§’иүІвҶ’жёёжҲҸз»“жқҹпјү';
    sysP += '\n- new_characters: еҲӣе»әж–°и§’иүІпјҲеӯҗе—ЈгҖҒжҠ•еҘ”иҖ…гҖҒж–°е®ҳе‘ҳзӯүпјү';
    sysP += '\n- faction_changes: \u4FEE\u6539\u52BF\u529B\u5C5E\u6027\uFF08strength_delta\u5B9E\u529B\uFF0Ceconomy_delta\u7ECF\u6D4E\uFF0CplayerRelation_delta\u5BF9\u7389\u5173\u7CFB\u3002strength\u964D\u81F30\u2192\u52BF\u529B\u8986\u706D\uFF09';
    sysP += '\n- faction_events: еҲӣйҖ еҠҝеҠӣй—ҙиҮӘдё»дәӢд»¶пјҲжҲҳдәү/иҒ”зӣҹ/ж”ҝеҸҳ/иЎҢеҶӣ/еӣҙеҹҺзӯүпјү';
    sysP += '\n  вҡ  ж¶үеҸҠиЎҢеҶӣ/еӣҙеҹҺзҡ„дәӢд»¶пјҢеҝ…йЎ»еңЁgeoDataдёӯжҸҗдҫӣең°зҗҶжҺЁз®—ж•°жҚ®пјҒ';
    sysP += '\n- faction_relation_changes: ж”№еҸҳеҠҝеҠӣй—ҙе…ізі»';
    sysP += '\n- party_changes: \u4FEE\u6539\u515A\u6D3E\u72B6\u6001\uFF08influence_delta\u5F71\u54CD\u529B\u3001new_status\u6D3B\u8DC3/\u5F0F\u5FAE/\u88AB\u538B\u5236/\u5DF2\u89E3\u6563\u3001new_leader\u9996\u9886\u66F4\u66FF\u3001new_agenda\u8BAE\u7A0B\u53D8\u5316\u3001new_shortGoal\u77ED\u671F\u76EE\u6807\u53D8\u5316\uFF09';
    sysP += '\n- class_changes: \u4FEE\u6539\u9636\u5C42\u72B6\u6001\uFF08satisfaction_delta\u6EE1\u610F\u5EA6\u3001influence_delta\u5F71\u54CD\u529B\u3001new_demands\u8BC9\u6C42\u968F\u5C40\u52BF\u53D8\u5316\u3001new_status\u5730\u4F4D\u53D8\u52A8\uFF09';
    sysP += '\n- army_changes: дҝ®ж”№йғЁйҳҹе…өеҠӣ/еЈ«ж°”/и®ӯз»ғпјҲйҷҚиҮі0вҶ’е…ЁеҶӣиҰҶжІЎпјү';
    sysP += '\n- item_changes: и®©и§’иүІиҺ·еҫ—жҲ–еӨұеҺ»зү©е“Ғ';
    sysP += '\n- era_state_delta: и°ғж•ҙж—¶д»ЈеҸӮж•°пјҲзӨҫдјҡзЁіе®ҡ/з»ҸжөҺ/йӣҶжқғ/еҶӣдәӢзӯүпјү';
    sysP += '\n- global_state_delta: и°ғж•ҙзЁҺеҺӢ';
    sysP += '\n- office_changes: е®ҳеҲ¶дәәдәӢеҸҳеҠЁпјҲappointд»»е‘Ҫ/dismissзҪўе…Қ/promoteжҷӢеҚҮ/demoteйҷҚзә§/transferи°ғд»»/evaluateиҖғиҜ„/reformж”№йқ©пјү';
    sysP += '\n- vassal_changes: е°ҒиҮЈе…ізі»еҸҳеҠЁпјҲestablishе»әз«Ӣ/breakи§ЈйҷӨ/change_tributeи°ғж•ҙиҙЎеҘүпјү';
    sysP += '\n- title_changes: еӨҙиЎ”зҲөдҪҚеҸҳеҠЁпјҲgrantеҶҢе°Ғ/revokeеүҘеӨә/inheritз»§жүҝйңҖжҢҮе®ҡfromжқҘжәҗи§’иүІ/promoteжҷӢеҚҮпјү';
    sysP += '\n- building_changes: е»әзӯ‘еҸҳеҠЁпјҲbuildе»әйҖ /upgradeеҚҮзә§/destroyжӢҶйҷӨпјҢйңҖжҢҮе®ҡterritoryе’Ңtypeпјү';
