// зҡҮеҹҺиҜҰжғ…еј№зӘ—
function openPalacePanel() {
  if (!P.palaceSystem || !P.palaceSystem.palaces) return;
  var palaces = P.palaceSystem.palaces;
  var _typeLabels = { main_hall:'еӨ–жңқдё»ж®ҝ', imperial_residence:'еёқеұ…е®«ж®ҝ', consort_residence:'еҗҺеҰғеұ…жүҖ', dowager:'еӨӘеҗҺ/еӨӘеҰғе®«', crown_prince:'еӨӘеӯҗе®«', ceremonial:'зӨјеҲ¶е»әзӯ‘', garden:'еӣӯжһ—иЎҢе®«', office:'еҶ…е»·еҠһе…¬', offering:'зҘӯзҘҖе®—еәҷ' };
  var _typeColors = { main_hall:'#ffd700', imperial_residence:'#e74c3c', consort_residence:'#9b59b6', dowager:'#d4a04c', crown_prince:'#3498db', ceremonial:'#95a5a6', garden:'#16a085', office:'#7f8c8d', offering:'#c0392b' };
  var html = '<div class="modal-bg show" id="_palaceDetailModal" onclick="if(event.target===this)this.remove()">';
  html += '<div class="modal-box" style="max-width:800px;max-height:85vh;overflow-y:auto;">';
  html += '<h3 style="color:var(--gold);margin:0 0 0.5rem;letter-spacing:0.1em;">рҹҸҜ ' + escHtml(P.palaceSystem.capitalName || 'зҡҮеҹҺ') + '</h3>';
  if (P.palaceSystem.capitalDescription) html += '<div style="font-size:0.78rem;color:var(--txt-s);line-height:1.7;padding:0.5rem;background:var(--bg-2);border-radius:6px;margin-bottom:0.8rem;">' + escHtml(P.palaceSystem.capitalDescription) + '</div>';
  // жҢүtypeеҲҶз»„
  var groups = {};
  palaces.forEach(function(p) { (groups[p.type] = groups[p.type] || []).push(p); });
  Object.keys(_typeLabels).forEach(function(t) {
    var grp = groups[t]; if (!grp || !grp.length) return;
    var color = _typeColors[t] || '#888';
    html += '<div style="margin-bottom:0.8rem;">';
    html += '<div style="font-size:0.85rem;color:' + color + ';font-weight:700;margin-bottom:0.3rem;padding:0.2rem 0;border-bottom:1px solid ' + color + '44;">в—Ҷ ' + _typeLabels[t] + ' (' + grp.length + ')</div>';
    grp.forEach(function(pal, pi) {
      var realIdx = palaces.indexOf(pal);
      html += '<div style="padding:0.5rem;margin-bottom:0.4rem;background:var(--bg-2);border-left:3px solid ' + color + ';border-radius:4px;">';
      html += '<div style="display:flex;justify-content:space-between;align-items:center;">';
      html += '<div><span style="font-size:0.95rem;color:' + color + ';font-weight:700;">' + escHtml(pal.name) + '</span>';
      if (pal.status && pal.status !== 'intact') {
        var sMap = { damaged:'жҚҹеқҸ', ruined:'иҚ’еәҹ', underconstruction:'еңЁе»ә' };
        html += '<span style="margin-left:6px;font-size:0.68rem;color:var(--red);">[' + (sMap[pal.status] || pal.status) + ']</span>';
      }
      if (pal.location) html += '<span style="margin-left:6px;font-size:0.66rem;color:var(--txt-d);">рҹ“Қ' + escHtml(pal.location) + '</span>';
      html += '</div>';
      html += '<div style="display:flex;gap:2px;">';
      html += '<button class="bt bsm" style="font-size:0.62rem;" onclick="_palaceAction(' + realIdx + ',\'renovate\')">дҝ®зј®</button>';
      html += '<button class="bt bsm" style="font-size:0.62rem;" onclick="_palaceAction(' + realIdx + ',\'reassign\')">з§»еұ…</button>';
      html += '</div>';
      html += '</div>';
      if (pal.function) html += '<div style="font-size:0.72rem;color:var(--txt-d);margin-top:2px;">' + escHtml(pal.function) + '</div>';
      if (pal.subHalls && pal.subHalls.length > 0) {
        html += '<div style="margin-top:4px;padding-left:10px;font-size:0.72rem;line-height:1.8;">';
        pal.subHalls.forEach(function(sh) {
          var roleLabel = { main:'дё»ж®ҝ', side:'еҒҸж®ҝ', attached:'йҷ„ж®ҝ' }[sh.role] || sh.role;
          var shColor = sh.role === 'main' ? '#ffd700' : sh.role === 'side' ? '#9b59b6' : '#16a085';
          html += '<div style="color:' + shColor + ';">в”ң <b>' + escHtml(sh.name) + '</b> <span style="color:var(--txt-d);">(' + roleLabel + ' ' + ((sh.occupants||[]).length) + '/' + (sh.capacity||1) + ')</span>';
          if (sh.occupants && sh.occupants.length) html += ' <span style="color:#4ade80;">' + sh.occupants.map(escHtml).join('гҖҒ') + '</span>';
          html += '</div>';
        });
        html += '</div>';
      }
      html += '</div>';
    });
    html += '</div>';
  });
  html += '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:0.8rem;">';
  html += '<button class="bt bp" onclick="_palaceNewBuild()">вҠ• дҝ®е»әж–°е®«ж®ҝ</button>';
  html += '<button class="bt bs" onclick="var m=document.getElementById(\'_palaceDetailModal\');if(m)m.remove();">е…ій—ӯ</button>';
  html += '</div>';
  html += '</div></div>';
  var tmp = document.createElement('div'); tmp.innerHTML = html; document.body.appendChild(tmp.firstChild);
}

function _palaceAction(idx, action) {
  var pal = P.palaceSystem && P.palaceSystem.palaces && P.palaceSystem.palaces[idx];
  if (!pal) return;
  if (action === 'renovate') {
    _palaceRenovateModal(pal);
    return;
  }
  if (action === 'reassign') {
    _palaceReassignModal(pal);
    return;
  }
}

/** дҝ®зј®еј№зӘ— */
function _palaceRenovateModal(pal) {
  var _old = document.getElementById('_palaceRenoModal'); if (_old) _old.remove();
  var statusMap = { damaged:'жҚҹеқҸ', ruined:'иҚ’еәҹ', underconstruction:'еңЁе»ә', intact:'е®ҢеҘҪ' };
  var html = '<div class="modal-bg show" id="_palaceRenoModal" onclick="if(event.target===this)this.remove()">';
  html += '<div class="modal-box" style="max-width:460px;">';
  html += '<h3 style="color:var(--gold);margin:0 0 0.5rem;letter-spacing:0.1em;">в—Һ дҝ®зј® ' + escHtml(pal.name) + '</h3>';
  html += '<div style="font-size:0.78rem;color:var(--txt-s);padding:0.5rem;background:var(--bg-2);border-radius:6px;margin-bottom:0.6rem;">еҪ“еүҚзҠ¶жҖҒпјҡ<b>' + (statusMap[pal.status]||'е®ҢеҘҪ') + '</b>' + (pal.lastRenovation?' В· дёҠж¬Ўдҝ®зј® T'+pal.lastRenovation:'') + '</div>';
  html += '<label style="font-size:0.78rem;color:var(--gold);">дҝ®зј®ж„ҸеӣҫпјҲе‘ҠзҹҘAIпјү</label>';
  html += '<textarea id="_palRenoDesc" rows="3" class="fd" style="width:100%;" placeholder="' + (pal.status === 'ruined' ? 'еҰӮпјҡиҚ’еәҹйҮҚе»әпјҢжҒўеӨҚи§„еҲ¶' : 'еҰӮпјҡж•ҙдҝ®жӯЈж®ҝеұӢз“ҰгҖҒйҮҚз»ҳеҪ©з»ҳгҖҒйҮҚй“әз –зҹі') + '"></textarea>';
  html += '<div style="display:flex;gap:8px;margin-top:0.6rem;justify-content:flex-end;">';
  html += '<button class="bt bs" onclick="var m=document.getElementById(\'_palaceRenoModal\');if(m)m.remove();">еҸ–ж¶Ҳ</button>';
  html += '<button class="bt bp" onclick="_palaceSubmitReno(&quot;' + encodeURIComponent(pal.name) + '&quot;)">жҸҗдәӨ</button>';
  html += '</div></div></div>';
  var tmp = document.createElement('div'); tmp.innerHTML = html; document.body.appendChild(tmp.firstChild);
}
function _palaceSubmitReno(palNameEnc) {
  var palName = decodeURIComponent(palNameEnc);
  var desc = ((document.getElementById('_palRenoDesc')||{}).value||'').trim() || 'дҝ®зј® ' + palName + 'пјҢжҒўеӨҚи§„еҲ¶дёҺеЁҒдёҘ';
  if (!GM._edictSuggestions) GM._edictSuggestions = [];
  GM._edictSuggestions.push({ source: '\u5BAB\u5EFA', from: palName, content: 'дҝ®зј® ' + palName + 'пјҡ' + desc, turn: GM.turn, used: false });
  toast('е·ІеҪ•е…ҘиҜҸд»Өе»әи®®еә“');
  if (typeof _renderEdictSuggestions === 'function') _renderEdictSuggestions();
  var m = document.getElementById('_palaceRenoModal'); if (m) m.remove();
}

/** з§»еұ…еј№зӘ—вҖ”вҖ”еҲ—еҮәзӣ®ж Үе®«ж®ҝзҡ„жүҖжңү subHall дҫӣйҖүжӢ© */
function _palaceReassignModal(pal) {
  var _old = document.getElementById('_palaceAssignModal'); if (_old) _old.remove();
  // ж”¶йӣҶеҪ“еүҚе®«ж®ҝзҡ„зҺ°жңүеұ…дҪҸиҖ…
  var currentOccupants = [];
  if (pal.subHalls) {
    pal.subHalls.forEach(function(sh) {
      (sh.occupants || []).forEach(function(n) { currentOccupants.push({ name: n, fromSubHall: sh }); });
    });
  }
  // ж”¶йӣҶжүҖжңү subHall дҪңдёәеҸҜиҝҒзӣ®ж ҮпјҲеҢ…жӢ¬е…¶д»–е®«ж®ҝзҡ„еұ…жүҖж®ҝпјү
  var allSubHalls = [];
  (P.palaceSystem.palaces || []).forEach(function(p) {
    if (p.type !== 'consort_residence' && p.type !== 'imperial_residence' && p.type !== 'main_hall') return;
    (p.subHalls || []).forEach(function(sh) {
      allSubHalls.push({ palace: p, subHall: sh });
    });
  });

  var html = '<div class="modal-bg show" id="_palaceAssignModal" onclick="if(event.target===this)this.remove()">';
  html += '<div class="modal-box" style="max-width:600px;max-height:85vh;overflow-y:auto;">';
  html += '<h3 style="color:var(--gold);margin:0 0 0.5rem;letter-spacing:0.1em;">в—Һ ' + escHtml(pal.name) + ' еҰғе«”з§»еұ…</h3>';

  if (currentOccupants.length === 0) {
    html += '<div style="padding:1rem;text-align:center;color:var(--txt-d);">жӯӨе®«ж®ҝжҡӮж— еұ…дҪҸиҖ…</div>';
    html += '<div style="text-align:center;margin-top:0.6rem;"><button class="bt bs" onclick="var m=document.getElementById(\'_palaceAssignModal\');if(m)m.remove();">е…ій—ӯ</button></div>';
  } else {
    html += '<div style="margin-bottom:0.6rem;">';
    html += '<label style="font-size:0.78rem;color:var(--gold);">в‘  йҖүжӢ©иҝҒеҮәиҖ…</label>';
    html += '<select id="_palAssignWho" class="fd" style="width:100%;">';
    currentOccupants.forEach(function(o) {
      html += '<option value="' + escHtml(o.name) + '">' + escHtml(o.name) + 'пјҲзҺ°еұ…пјҡ' + escHtml(o.fromSubHall.name) + 'пјү</option>';
    });
    html += '</select></div>';

    html += '<div style="margin-bottom:0.6rem;">';
    html += '<label style="font-size:0.78rem;color:var(--gold);">в‘Ў йҖүжӢ©зӣ®ж Үеұ…жүҖ</label>';
    html += '<select id="_palAssignTo" class="fd" style="width:100%;">';
    allSubHalls.forEach(function(t) {
      var occ = t.subHall.occupants || [];
      var full = occ.length >= (t.subHall.capacity || 1);
      var roleLabel = { main:'дё»ж®ҝ', side:'еҒҸж®ҝ', attached:'йҷ„ж®ҝ' }[t.subHall.role] || t.subHall.role;
      var dispText = t.palace.name + 'В·' + t.subHall.name + 'пјҲ' + roleLabel + ' ' + occ.length + '/' + (t.subHall.capacity||1) + 'пјү' + (full ? ' [ж»Ў]' : '');
      html += '<option value="' + escHtml(t.palace.name) + '|' + escHtml(t.subHall.name) + '"' + (full ? ' disabled' : '') + '>' + escHtml(dispText) + '</option>';
    });
    html += '</select></div>';

    html += '<div style="margin-bottom:0.6rem;">';
    html += '<label style="font-size:0.78rem;color:var(--gold);">в‘ў еҺҹеӣ иҜҙжҳҺпјҲAIжҚ®жӯӨз”ҹжҲҗеҸҷдәӢпјү</label>';
    html += '<textarea id="_palAssignReason" rows="2" class="fd" style="width:100%;" placeholder="еҰӮпјҡжҷӢиҙөеҰғдҪҚпјҢз§»еұ…еӮЁз§Җе®«жӯЈж®ҝпјӣжҲ–пјҡеӨұе® пјҢиҝҒеҮәд№ҫжё…е®«"></textarea>';
    html += '</div>';

    html += '<div style="display:flex;gap:8px;margin-top:0.6rem;justify-content:flex-end;">';
    html += '<button class="bt bs" onclick="var m=document.getElementById(\'_palaceAssignModal\');if(m)m.remove();">еҸ–ж¶Ҳ</button>';
    html += '<button class="bt bp" onclick="_palaceSubmitReassign()">жҸҗдәӨ</button>';
    html += '</div>';
  }
  html += '</div></div>';
  var tmp = document.createElement('div'); tmp.innerHTML = html; document.body.appendChild(tmp.firstChild);
}

function _palaceSubmitReassign() {
  var who = (document.getElementById('_palAssignWho')||{}).value || '';
  var toVal = (document.getElementById('_palAssignTo')||{}).value || '';
  var reason = ((document.getElementById('_palAssignReason')||{}).value||'').trim();
  if (!who || !toVal) { toast('иҜ·йҖүжӢ©иҝҒеҮәиҖ…дёҺзӣ®ж Үеұ…жүҖ'); return; }
  var parts = toVal.split('|');
  var toPal = parts[0], toSubHall = parts[1];
  if (!GM._edictSuggestions) GM._edictSuggestions = [];
  var content = 'и°ғ ' + who + ' з§»еұ… ' + toPal + 'В·' + toSubHall + (reason ? 'вҖ”вҖ”' + reason : '');
  GM._edictSuggestions.push({ source: '\u5BAB\u5EFA', from: toPal, content: content, turn: GM.turn, used: false });
  toast('е·ІеҪ•е…ҘиҜҸд»Өе»әи®®еә“');
  if (typeof _renderEdictSuggestions === 'function') _renderEdictSuggestions();
  var m = document.getElementById('_palaceAssignModal'); if (m) m.remove();
}

function _palaceNewBuild() {
  var name = window.prompt('ж–°е»әе®«ж®ҝеҗҚпјҡ', '');
  if (!name || !name.trim()) return;
  var desc = window.prompt('иҜҘе®«ж®ҝз”ЁйҖ”гҖҒи§„жЁЎгҖҒдҪҚзҪ®пјҲе‘ҠзҹҘAIпјүпјҡ', '');
  if (!desc || !desc.trim()) return;
  if (!GM._edictSuggestions) GM._edictSuggestions = [];
  GM._edictSuggestions.push({
    source: '\u5BAB\u5EFA',
    from: 'зҡҮеҹҺ',
    content: 'ж–°е»әе®«ж®ҝгҖҗ' + name.trim() + 'гҖ‘пјҡ' + desc.trim() + 'гҖӮвҖ”вҖ”иҜ·AIеҲӨе®ҡе»әйҖ еҗҲзҗҶжҖ§гҖҒжҲҗжң¬гҖҒе·ҘжңҹдёҺеЁҒд»ӘеҪұе“ҚпјҢзәіе…ҘзҡҮеҹҺгҖӮ',
    turn: GM.turn,
    used: false
  });
  toast('е·ІеҪ•е…ҘиҜҸд»Өе»әи®®еә“пјҢиҜ·еңЁиҜҸд»ӨеҢәзәіе…ҘеҗҺйўҒиҜҸ');
  if (typeof _renderEdictSuggestions === 'function') _renderEdictSuggestions();
  var m = document.getElementById('_palaceDetailModal'); if (m) m.remove();
}

// ============================================================
//  жіЁеҶҢ endTurn й’©еӯҗпјҲжӣҝд»ЈеҺҹжңүзҡ„еҢ…иЈ…й“ҫпјү
// ============================================================

// й’©еӯҗ 1: е®ҳеҲ¶ж¶ҲиҖ—пјҲеҺҹ _origEndTurnпјү
EndTurnHooks.register('before', function() {
  if(P.officeConfig&&P.officeConfig.costVariables&&P.officeConfig.costVariables.length>0&&GM.officeTree){
    var td=0,to=0;
    function countOff(tree){tree.forEach(function(d){td++;to+=(d.positions||[]).filter(function(p){return p.holder;}).length;if(d.subs)countOff(d.subs);});}
    countOff(GM.officeTree);
    var shortfall=[];
    P.officeConfig.costVariables.forEach(function(cv){
      var cost=(cv.perDept||0)*td+(cv.perOfficial||0)*to;
      if(GM.vars[cv.variable]){
        GM.vars[cv.variable].value=clamp(GM.vars[cv.variable].value-cost,GM.vars[cv.variable].min,GM.vars[cv.variable].max);
        if(GM.vars[cv.variable].value<=GM.vars[cv.variable].min+5)shortfall.push(cv.variable);
      }
    });
    if(shortfall.length>0)addEB("е®ҳеҲ¶еҚұжңә",shortfall.join(",")+"дёҚи¶і");
  }
}, 'е®ҳеҲ¶ж¶ҲиҖ—');

// й’©еӯҗ 2: еҘҸи®®жү№еӨҚпјҲеҺҹ _origEndTurn2пјү
EndTurnHooks.register('before', function() {
  if(GM.memorials&&GM.memorials.length>0){
    GM.memorials.forEach(function(m){
      var statusText=m.status==="approved"?"еҮҶеҘҸ":m.status==="rejected"?"й©іеӣһ":"жңӘжү№еӨҚ";
      var exists=GM.jishiRecords.find(function(r){return r.turn===GM.turn&&r.char===m.from&&r.playerSaid&&r.playerSaid.indexOf("еҘҸз–Ҹ")>=0;});
      if(!exists)GM.jishiRecords.push({turn:GM.turn,char:m.from,playerSaid:"\u594F\u758F("+m.type+"): "+m.content,npcSaid:"\u6279\u590D: "+statusText+(m.reply?" | "+m.reply:"")});
    });
    renderJishi();
  }
}, 'еҘҸи®®жү№еӨҚ');

// й’©еӯҗ 3: AIдёҠдёӢж–ҮжіЁе…Ҙ - еү§жң¬ж–ҮйЈҺпјҲеҺҹ _origEndTurn3пјү
EndTurnHooks.register('before', function() {
  if(P.ai.key){
    GM._origPrompt=P.ai.prompt;
    var fullPrompt=P.ai.prompt||DEFAULT_PROMPT;
    var sc=findScenarioById(GM.sid);

    if(sc&&sc.scnStyle)fullPrompt+="\nжң¬еү§жң¬ж–ҮйЈҺ: "+sc.scnStyle;
    if(sc&&sc.scnStyleRule)fullPrompt+="\nж–ҮйЈҺи§„еҲҷ: "+sc.scnStyleRule;
    // 4.3b: ж–ҮйЈҺжҢҮд»Өжҳ е°„
    var _styleMap = {
      'ж–ҮеӯҰеҢ–': 'ж–ҮиҫһдјҳзҫҺпјҢе–„з”ЁжҜ”е–»е’Ңж„ҸиұЎпјҢжғ…ж„ҹе……жІӣ',
      'еҸІд№ҰдҪ“': 'д»ҝгҖҠиө„жІ»йҖҡйүҙгҖӢзәӘдәӢжң¬жң«дҪ“пјҢиЁҖз®Җж„Ҹиө…пјҢйҮҚдәӢе®һиҪ»жёІжҹ“',
      'жҲҸеү§еҢ–': 'зҹӣзӣҫеҶІзӘҒе°–й”җпјҢдәәзү©еҜ№иҜқз”ҹеҠЁпјҢе–„з”ЁжӮ¬еҝөе’ҢеҸҚиҪ¬',
      'з« еӣһдҪ“': 'д»ҝгҖҠдёүеӣҪжј”д№үгҖӢз« еӣһдҪ“е°ҸиҜҙпјҢжҜҸж®өејҖеӨҙеҸҜз”ЁеҜ№д»—еӣһзӣ®пјҢж–ҮзҷҪеӨ№жқӮ',
      'зәӘдј дҪ“': 'д»ҝгҖҠеҸІи®°гҖӢзәӘдј дҪ“пјҢд»Ҙдәәзү©дёәдёӯеҝғпјҢ"еӨӘеҸІе…¬жӣ°"ејҸиҜ„и®ә',
      'зҷҪиҜқж–Ү': 'зҺ°д»ЈзҷҪиҜқж–ҮйЈҺж јпјҢйҖҡдҝ—жҳ“жҮӮпјҢиҠӮеҘҸжҳҺеҝ«'
    };
    if(P.conf.style&&_styleMap[P.conf.style])fullPrompt+="\nеҸҷдәӢж–ҮйЈҺ: "+_styleMap[P.conf.style];
    if(P.conf.customStyle)fullPrompt+="\nиҮӘе®ҡд№үж–ҮйЈҺ: "+P.conf.customStyle;

    if(sc&&sc.refText)fullPrompt+="\n\u53C2\u8003: "+sc.refText;
    if(P.conf.refText)fullPrompt+="\n\u5168\u5C40\u53C2\u8003: "+P.conf.refText;

    if(P.world.entries&&P.world.entries.length>0){
      fullPrompt+="\n\n=== дё–з•Ңи®ҫе®ҡ ===";
      P.world.entries.forEach(function(e){
        if(e.category&&e.title&&e.content)fullPrompt+="\n["+e.category+"] "+e.title+": "+e.content;
      });
    }

    P.ai.prompt=fullPrompt;
  }
}, 'AIдёҠдёӢж–Ү-еү§жң¬ж–ҮйЈҺ');

// й’©еӯҗ 4: жҒўеӨҚеҺҹе§Ӣprompt
EndTurnHooks.register('after', function() {
  if(GM._origPrompt!==undefined){
    P.ai.prompt=GM._origPrompt;
    delete GM._origPrompt;
  }
}, 'жҒўеӨҚеҺҹе§Ӣprompt');

// й’©еӯҗ 5: AIдёҠдёӢж–ҮжіЁе…Ҙ - иө·еұ…жіЁпјҲеҺҹ _origEndTurn5пјү
EndTurnHooks.register('before', function() {
  if(P.ai.key&&GM.conv.length>0){
    var qijuLb=P.conf.qijuLookback||5;
    var recentQ=GM.qijuHistory.slice(-qijuLb);
    if(recentQ.length>0){
      var qijuText="\n\n=== иҝ‘"+qijuLb+"еӣһеҗҲиө·еұ…жіЁ ===\n";
      recentQ.forEach(function(q){
        qijuText+="T"+q.turn+" "+q.time+":\n";
        if(q.edicts){
          if(q.edicts.political)qijuText+="  ж”ҝ: "+q.edicts.political+"\n";
          if(q.edicts.military)qijuText+="  еҶӣ: "+q.edicts.military+"\n";
          if(q.edicts.diplomatic)qijuText+="  еӨ–: "+q.edicts.diplomatic+"\n";
          if(q.edicts.economic)qijuText+="  з»Ҹ: "+q.edicts.economic+"\n";
        }
        if(q.xinglu)qijuText+="  иЎҢ: "+q.xinglu+"\n";
      });
      if(!GM._origPrompt2)GM._origPrompt2=P.ai.prompt;
      P.ai.prompt=(P.ai.prompt||"")+qijuText;
    }
  }
}, 'AIдёҠдёӢж–Ү-иө·еұ…жіЁ');

